module Lexer

# 1 "Lexer.fsl"
 
open System
open FSharp.Text.Lexing
open Parser  // Import token types from generated Parser module

// Helper to get lexeme as string
let lexeme (lexbuf: LexBuffer<_>) =
    LexBuffer<_>.LexemeString lexbuf

/// Classify a multi-character operator token into precedence bucket
/// Based on OCaml's INFIXOP0-4 approach: first character determines precedence
let classifyOperator (op: string) =
    let eff = op.TrimStart('.')
    if eff.Length = 0 then INFIXOP3 op  // pure dots -> multiplicative level
    elif eff.Length >= 2 && eff.[0] = '*' && eff.[1] = '*' then INFIXOP4 op
    else
        match eff.[0] with
        | '=' | '<' | '>' | '|' | '&' | '$' | '!' -> INFIXOP0 op
        | '@' | '^' -> INFIXOP1 op
        | '+' | '-' -> INFIXOP2 op
        | '*' | '/' | '%' -> INFIXOP3 op
        | _ -> INFIXOP0 op  // fallback to comparison level

/// Initialize position tracking for the lexbuf
let setInitialPos (lexbuf: LexBuffer<_>) (filename: string) =
    lexbuf.EndPos <- {
        pos_fname = filename
        pos_lnum = 1
        pos_bol = 0
        pos_cnum = 0
        pos_orig_lnum = 1
    }

